    // === DOWNLOAD DOS DADOS ATUAIS EM XLSX ===
    function downloadXLSX() {
        if (!projects || projects.length === 0) {
            alert("Não há dados carregados para baixar!");
            return;
        }

        // Mapear objetos com chaves amigáveis em português
        const friendlyData = projects.map(p => {
            const mapped = {};
            const friendlyHeaders = {
                id: "ID",
                n_antiga: "Nº Antiga",
                planilha: "Planilha",
                mes: "Mês",
                ano: "Ano",
                data_instrucao: "Data Instrução",
                responsavel: "Responsável",
                tipo_contrato: "Tipo de Contrato",
                fundacao: "Fundação",
                tipo_projeto: "Tipo de Projeto",
                tipo_projeto_norm: "Tipo de Projeto (Normalizado)",
                situacao: "Situação",
                situacao_norm: "Situação (Normalizada)",
                nup: "NUP",
                coordenador: "Coordenador",
                contato_coordenador: "Contato Coordenador",
                unidade: "Unidade",
                unid_norm: "Unidade (Normalizada)",
                subunidade: "Subunidade",
                fiscal: "Fiscal",
                participes: "Partícipes",
                titulo: "Projeto / Título",
                registro_portal: "Registro Portal",
                id_projeto_fundacao: "ID Projeto Fundação",
                valor: "Valor (R$)",
                taxa_ufsm: "Taxa UFSM (R$)",
                numero_contrato: "Número do Contrato",
                vigencia_inicial: "Vigência Inicial",
                vigencia_final: "Vigência Final",
                remuneracao_pi: "Remuneração PI",
                propriedade_intelectual: "Propriedade Intelectual",
                financiador: "Financiador"
            };

            // Garantir que as colunas fiquem na ordem que queremos
            const keysOrder = [
                'id', 'n_antiga', 'planilha', 'ano', 'mes', 'data_instrucao', 
                'responsavel', 'tipo_contrato', 'fundacao', 'tipo_projeto', 
                'tipo_projeto_norm', 'situacao', 'situacao_norm', 'nup', 
                'coordenador', 'contato_coordenador', 'unidade', 'unid_norm', 
                'subunidade', 'fiscal', 'participes', 'titulo', 'registro_portal', 
                'id_projeto_fundacao', 'valor', 'taxa_ufsm', 'numero_contrato', 
                'vigencia_inicial', 'vigencia_final', 'remuneracao_pi', 
                'propriedade_intelectual', 'financiador'
            ];

            keysOrder.forEach(key => {
                const header = friendlyHeaders[key] || key;
                mapped[header] = p[key] !== undefined ? p[key] : "";
            });

            // Se o projeto tiver chaves adicionais não listadas em keysOrder
            Object.keys(p).forEach(key => {
                if (!keysOrder.includes(key)) {
                    const header = friendlyHeaders[key] || key;
                    mapped[header] = p[key] !== undefined ? p[key] : "";
                }
            });

            return mapped;
        });

        try {
            // Criar a planilha e o workbook usando o SheetJS
            const worksheet = XLSX.utils.json_to_sheet(friendlyData);
            const workbook = XLSX.utils.book_new();
            XLSX.utils.book_append_sheet(workbook, worksheet, "Projetos");

            // Gerar o download usando data URL base64 para compatibilidade com o protocolo file:// no Chrome
            const filename = `fonte_dados_projetos_${activeSourceType}_${new Date().toISOString().slice(0, 10)}.xlsx`;
            const wbout = XLSX.write(workbook, { bookType: 'xlsx', type: 'base64' });
            const dataUrl = 'data:application/vnd.openxmlformats-officedocument.spreadsheetml.sheet;base64,' + wbout;
            
            const link = document.createElement("a");
            link.href = dataUrl;
            link.download = filename;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            console.log(`Fonte de dados (${activeSourceType}) baixada com sucesso como XLSX via Data URL.`);
        } catch (err) {
            console.error(err);
            alert(`Erro ao exportar arquivo XLSX: ${err.message}`);
        }
    }

    // === PROCESSAMENTO DOS FILTROS (VISÃO GERAL) ===
    function applyFiltersVisaoGeral() {
        // Atualiza dinamicamente as opções com base no relacionamento entre os filtros
        populateGlobalFilterOptions();

        const valAno = document.getElementById('global-filter-ano') ? document.getElementById('global-filter-ano').value : '';
        selectedYears = valAno ? [valAno] : [];
        selectedContractType = document.getElementById('global-filter-contrato') ? document.getElementById('global-filter-contrato').value : '';
        selectedCoordinator = document.getElementById('global-filter-coordenador') ? document.getElementById('global-filter-coordenador').value : '';

        filteredProjects = projects.filter(p => {
            const matchAno = !valAno || (p.ano && p.ano.toString() === valAno);
            const matchContrato = !selectedContractType || p.tipo_contrato === selectedContractType;
            const matchCoord = !selectedCoordinator || p.coordenador === selectedCoordinator;
            return matchAno && matchContrato && matchCoord;
        });

        updateDashboard();
    }

    // === PROCESSAMENTO DOS FILTROS (EXPLORADOR) ===
    function applyFiltersExplorador() {
        // Atualiza dinamicamente as opções com base no relacionamento entre os filtros
        populateExploradorFilterOptions();

        const searchBox = document.getElementById('search-box');
        const query = searchBox ? searchBox.value.toLowerCase().trim() : '';
        
        const selectAno = document.getElementById('filter-ano');
        const fAno = selectAno ? selectAno.value : '';
        
        const selectContrato = document.getElementById('filter-contrato');
        const fContrato = selectContrato ? selectContrato.value : '';
        
        const selectUnid = document.getElementById('filter-unidade');
        const fUnid = selectUnid ? selectUnid.value : '';
        
        const selectCoord = document.getElementById('filter-coordenador');
        const fCoord = selectCoord ? selectCoord.value : '';

        filteredProjects = projects.filter(p => {
            const matchQuery = !query || 
                (p.titulo && p.titulo.toLowerCase().includes(query)) ||
                (p.coordenador && p.coordenador.toLowerCase().includes(query)) ||
                (p.fiscal && p.fiscal.toLowerCase().includes(query)) ||
                (p.participes && p.participes.toLowerCase().includes(query)) ||
                (p.id && p.id.toString().includes(query));

            const matchAno = !fAno || (p.ano && p.ano.toString() === fAno);
            const matchContrato = !fContrato || p.tipo_contrato === fContrato;
            const matchUnid = !fUnid || p.unid_norm === fUnid;
            const matchCoord = !fCoord || p.coordenador === fCoord;

            return matchQuery && matchAno && matchContrato && matchUnid && matchCoord;
        });

        currentPage = 1; // Voltar para a página 1 ao filtrar
        applySorting();
        renderTable();
    }

    function applyAnaliseFilters() {
        populateAnaliseFilterOptions();

        const selectAno = document.getElementById('analise-filter-ano');
        const fAno = selectAno ? selectAno.value : '';

        const selectContrato = document.getElementById('analise-filter-contrato');
        const fContrato = selectContrato ? selectContrato.value : '';

        filteredProjects = projects.filter(p => {
            const matchAno = !fAno || (p.ano && p.ano.toString() === fAno);
            const matchContrato = !fContrato || (p.tipo_contrato && p.tipo_contrato === fContrato);
            return matchAno && matchContrato;
        });

        renderAdvancedAnalysis();
    }

    // === ORDENACAO DOS DADOS ===
    function applySorting() {
        filteredProjects.sort((a, b) => {
            let valA = a[sortColumn];
            let valB = b[sortColumn];

            // Tratar strings vazias ou nulas
            if (valA === null || valA === undefined) valA = '';
            if (valB === null || valB === undefined) valB = '';

            // Se for coluna de valor financeiro
            if (sortColumn === 'valor' || sortColumn === 'taxa_ufsm') {
                return sortDirection === 'asc' ? valA - valB : valB - valA;
            }

            // Se for ID numérico
            if (sortColumn === 'id') {
                const numA = parseInt(valA) || 0;
                const numB = parseInt(valB) || 0;
                return sortDirection === 'asc' ? numA - numB : numB - numA;
            }

            // Ordenação alfabética
            valA = valA.toString().toLowerCase();
            valB = valB.toString().toLowerCase();

            if (valA < valB) return sortDirection === 'asc' ? -1 : 1;
            if (valA > valB) return sortDirection === 'asc' ? 1 : -1;
            return 0;
        });
    }

    // === ATUALIZAR TODOS OS DADOS E KPIS DO DASHBOARD ===
    function updateDashboard() {
        // Calcular KPIs baseados no conjunto de dados filtrado
        const totalProjetos = filteredProjects.length;
        
        let valorTotal = 0;
        let vigentesCount = 0;
        let taxaTotal = 0;
        let taxaValidos = 0; // Contar quantos projetos têm taxa especificada para média

        filteredProjects.forEach(p => {
            valorTotal += (p.valor || 0);
            taxaTotal += (p.taxa_ufsm || 0);
            
            if (p.situacao_norm === 'Em vigência') {
                vigentesCount++;
            }
            if (p.taxa_ufsm > 0) {
                taxaValidos++;
            }
        });

        const valorMedio = totalProjetos > 0 ? (valorTotal / totalProjetos) : 0;
        const vigentesPercent = totalProjetos > 0 ? Math.round((vigentesCount / totalProjetos) * 100) : 0;
        const taxaMediaPercent = valorTotal > 0 ? ((taxaTotal / valorTotal) * 100).toFixed(1) : "0.0";

        // Animar e atualizar os KPIs na tela
        animateValue('kpi-total-projetos', 0, totalProjetos, 1000, false);
        animateValue('kpi-valor-total', 0, valorTotal, 1200, true);
        animateValue('kpi-valor-medio', 0, valorMedio, 1200, true);
        animateValue('kpi-vigencia-ativa', 0, vigentesCount, 1000, false);
        animateValue('kpi-taxa-total', 0, taxaTotal, 1200, true);

        // Subtítulos dos KPIs
        const kpiVigenciaPercent = document.getElementById('kpi-vigencia-percent');
        if (kpiVigenciaPercent) {
            kpiVigenciaPercent.innerHTML = `<span>${vigentesPercent}% do portfólio ativo</span>`;
        }
        const kpiTaxaPercent = document.getElementById('kpi-taxa-percent');
        if (kpiTaxaPercent) {
            kpiTaxaPercent.innerHTML = `<span>${taxaMediaPercent}% de retorno médio</span>`;
        }

        // Renderizar/Atualizar os Gráficos
        updateDashboardCharts();
    }

    // === ANIMACAO DOS VALORES DE KPI (COUNT UP) ===
    function animateValue(id, start, end, duration, isCurrency) {
        const obj = document.getElementById(id);
        if (!obj) return;
        
        if (animateTimers[id]) {
            clearInterval(animateTimers[id]);
        }
        
        const range = end - start;
        let current = start;
        const increment = end > start ? Math.ceil(range / (duration / 16)) : Math.floor(range / (duration / 16));
        const stepTime = 16; // Aprox 60fps
        
        // Se for uma captação grande, ajustamos o incremento mínimo
        const step = Math.max(increment, 1);
        
        animateTimers[id] = setInterval(() => {
            current += step;
            if ((step > 0 && current >= end) || (step < 0 && current <= end)) {
                current = end;
                clearInterval(animateTimers[id]);
                delete animateTimers[id];
            }
            
            if (isCurrency) {
                obj.innerText = formatCurrency(current);
            } else {
                obj.innerText = current.toLocaleString('pt-BR');
            }
        }, stepTime);
    }

    function formatCurrency(val) {
        return val.toLocaleString('pt-BR', { style: 'currency', currency: 'BRL', maximumFractionDigits: 0 });
    }

