    // === PROCESSADOR DE UPLOAD DE NOVO ARQUIVO (CSV / XLSX / XLS) ===
    function processUploadedFile(file) {
        const nameLower = file.name.toLowerCase();
        
        if (nameLower.endsWith('.xlsx') || nameLower.endsWith('.xls')) {
            console.log("Processando arquivo Excel via SheetJS...");
            const reader = new FileReader();
            reader.onload = (e) => {
                try {
                    const data = new Uint8Array(e.target.result);
                    const workbook = XLSX.read(data, {type: 'array'});
                    const sheets = {};
                    workbook.SheetNames.forEach(sheetName => {
                        const worksheet = workbook.Sheets[sheetName];
                        const rows = XLSX.utils.sheet_to_json(worksheet, {header: 1});
                        if (rows && rows.length > 0) {
                            sheets[sheetName] = rows;
                        }
                    });
                    loadWorkbookData(sheets, file.name, 'upload');
                } catch (err) {
                    console.error(err);
                    alert("Erro ao decodificar a planilha Excel: " + err.message);
                }
            };
            reader.readAsArrayBuffer(file);
            return;
        }

        if (nameLower.endsWith('.csv')) {
            console.log("Processando arquivo CSV...");
            const reader = new FileReader();
            
            // Lemos primeiro como UTF-8
            reader.readAsText(file, "UTF-8");

            reader.onload = (event) => {
                let text = event.target.result;
                
                // Se contiver muitos caracteres corrompidos, tentar ler como ISO-8859-1 (ANSI)
                if (text.includes('') || text.includes('')) {
                    const retryReader = new FileReader();
                    retryReader.readAsText(file, "ISO-8859-1");
                    retryReader.onload = (e) => parseAndLoadCSVData(e.target.result, file.name);
                } else {
                    parseAndLoadCSVData(text, file.name);
                }
            };
            return;
        }

        alert("Erro: Apenas arquivos CSV, XLSX ou XLS são suportados!");
    }

    // === CLIENT-SIDE CSV PARSER COM RESOLUCAO DINAMICA DE COLUNAS ===
    function parseAndLoadCSVData(csvText, filename) {
        try {
            console.log("Iniciando parse client-side do CSV...");
            const delimiter = detectDelimiter(csvText);
            console.log(`Delimitador detectado: "${delimiter}"`);

            const rows = parseCSVLines(csvText, delimiter);
            const sheets = {};
            sheets[filename] = rows; // CSV treats the file as a single sheet named after the file
            loadWorkbookData(sheets, filename, 'upload');
        } catch (err) {
            console.error(err);
            alert(`Erro grave ao analisar o arquivo CSV: ${err.message}`);
        }
    }

    // === DETECTAR DELIMITADOR DO CSV ===
    function detectDelimiter(csvText) {
        let delimiter = ",";
        const firstLine = csvText.split('\n')[0];
        if (firstLine.split(';').length > firstLine.split(',').length) {
            delimiter = ";";
        }
        return delimiter;
    }

    // === BUSCAR E SINCRONIZAR PLANILHA DO GOOGLE SHEETS ===
    function syncGoogleSheet(url) {
        const matches = url.match(/\/d\/([a-zA-Z0-9-_]+)/);
        if (!matches) {
            alert("Link do Google Planilhas inválido. Copie o link completo de compartilhamento!");
            return;
        }
        const spreadsheetId = matches[1];
        
        const gidMatches = url.match(/gid=([0-9]+)/);
        const gid = gidMatches ? gidMatches[1] : null;
        
        const csvUrl = gid 
            ? `https://docs.google.com/spreadsheets/d/${spreadsheetId}/export?format=csv&gid=${gid}&t=${Date.now()}&rand=${Math.random()}`
            : `https://docs.google.com/spreadsheets/d/${spreadsheetId}/export?format=csv&t=${Date.now()}&rand=${Math.random()}`;

        const btnSync = document.getElementById('btn-sync-sheet');
        const originalText = btnSync ? btnSync.innerText : "Sincronizar";
        if (btnSync) {
            btnSync.innerText = "Buscando...";
            btnSync.disabled = true;
        }

        fetch(csvUrl, { cache: "no-store", headers: { "Cache-Control": "no-cache", "Pragma": "no-cache" } })
            .then(response => {
                if (!response.ok) throw new Error("Não foi possível acessar a planilha. Verifique o compartilhamento da planilha.");
                return response.text();
            })
            .then(csvText => {
                const delimiter = detectDelimiter(csvText);
                const rows = parseCSVLines(csvText, delimiter);
                
                // Salvar URL e timestamp de sincronização
                localStorage.setItem('sheet_url', url);
                const now = new Date();
                const timeString = now.toLocaleDateString('pt-BR') + ' às ' + now.toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'});
                localStorage.setItem('sheet_sync_time', timeString);

                const sheets = {};
                sheets["Google Sheets"] = rows;
                loadWorkbookData(sheets, "Google Sheets", 'sheet');
                
                // Forçar seleção visual do radio button
                const radioSheet = document.querySelector('input[name="source-type"][value="sheet"]');
                if (radioSheet) radioSheet.checked = true;
            })
            .catch(err => {
                console.error(err);
                alert("Erro ao sincronizar com Google Sheets: " + err.message + "\n\nIMPORTANTE: A planilha deve estar compartilhada publicamente como 'Qualquer pessoa com o link pode ler'!");
            })
            .finally(() => {
                if (btnSync) {
                    btnSync.innerText = originalText;
                    btnSync.disabled = false;
                }
            });
    }

    // === APLICAR A FONTE DE DADOS SELECIONADA E ATUALIZAR EXIBICAO ===
    function applyActiveSource(sourceType, alertUser = true) {
        activeSourceType = sourceType;
        localStorage.setItem('source_type', sourceType);

        let dataToLoad = [];
        let statusText = "Dados Padrão";
        let statusBadgeColor = "rgba(var(--primary-rgb), 0.12)";
        let statusBadgeTextColor = "var(--primary)";
        let syncTimeText = "Carregamento Inicial";
        
        if (sourceType === 'default') {
            if ((!originalProjects || originalProjects.length === 0) && typeof initialProjectsData !== 'undefined') {
                originalProjects = initialProjectsData.map(p => {
                    const extractedAno = getYearFromVigencia(p.vigencia_inicial) || p.ano;
                    const extractedMes = getMonthFromVigencia(p.vigencia_inicial) || p.mes;
                    return {
                        ...p,
                        ano: extractedAno,
                        mes: extractedMes,
                        coordenador: normalizeCoordinatorName(p.coordenador),
                        titulo: (p.registro_portal && p.registro_portal !== "---" && !fixEncoding(p.titulo).startsWith(p.registro_portal)) ? `${p.registro_portal} - ${fixEncoding(p.titulo)}` : fixEncoding(p.titulo),
                        situacao: fixEncoding(p.situacao),
                        situacao_norm: fixEncoding(p.situacao_norm),
                        tipo_projeto: fixEncoding(p.tipo_projeto),
                        tipo_projeto_norm: fixEncoding(p.tipo_projeto_norm),
                        fundacao: fixEncoding(p.fundacao),
                        unidade: fixEncoding(p.unidade),
                        unid_norm: fixEncoding(p.unid_norm),
                        subunidade: fixEncoding(p.subunidade),
                        fiscal: fixEncoding(p.fiscal),
                        participes: fixEncoding(p.participes),
                        financiador: normalizeFinanciador(p.financiador),
                        tipo_contrato: fixEncoding(p.tipo_contrato)
                    };
                });
            }
            dataToLoad = [...originalProjects];
            statusText = "Dados Padrão (Local)";
            statusBadgeColor = "rgba(var(--primary-rgb), 0.12)";
            statusBadgeTextColor = "var(--primary)";
            syncTimeText = "Original do Sistema";
        } else if (sourceType === 'sheet') {
            if (sheetProjects && sheetProjects.length > 0) {
                dataToLoad = [...sheetProjects];
                statusText = "Google Sheets (Sincronizado)";
                statusBadgeColor = "rgba(0, 242, 161, 0.12)";
                statusBadgeTextColor = "var(--success)";
                const savedTime = localStorage.getItem('sheet_sync_time') || "Recentemente";
                syncTimeText = `Planilha Online (${savedTime})`;
            } else {
                const savedSheetUrl = localStorage.getItem('sheet_url');
                if (savedSheetUrl) {
                    dataToLoad = [...originalProjects]; // Temporário
                    setTimeout(() => syncGoogleSheet(savedSheetUrl), 100);
                } else {
                    dataToLoad = [...originalProjects];
                    if (alertUser) alert("Nenhuma planilha do Google Sheets vinculada! Vincula uma no formulário ao lado.");
                    activeSourceType = 'default';
                    localStorage.setItem('source_type', 'default');
                    const radioDefault = document.querySelector('input[name="source-type"][value="default"]');
                    if (radioDefault) radioDefault.checked = true;
                }
            }
        } else if (sourceType === 'upload') {
            if (uploadedProjects && uploadedProjects.length > 0) {
                dataToLoad = [...uploadedProjects];
                const fileName = localStorage.getItem('uploaded_file_name') || "Arquivo Local";
                statusText = `Arquivo Local: ${fileName}`;
                statusBadgeColor = "rgba(56, 189, 248, 0.12)";
                statusBadgeTextColor = "var(--info)";
                const savedTime = localStorage.getItem('upload_sync_time') || "Recentemente";
                syncTimeText = `Importado local (${savedTime})`;
            } else {
                dataToLoad = [...originalProjects];
                if (alertUser) alert("Nenhum arquivo local foi importado ainda! Use a zona de upload.");
                activeSourceType = 'default';
                localStorage.setItem('source_type', 'default');
                const radioDefault = document.querySelector('input[name="source-type"][value="default"]');
                if (radioDefault) radioDefault.checked = true;
            }
        }

        projects = dataToLoad;
        filteredProjects = [...projects];
        currentPage = 1;
        selectedYears = [];
        selectedContractType = "";
        selectedCoordinator = "";

        // Sincronizar controles visuais do menu Importar
        const badge = document.getElementById('source-status-badge');
        if (badge) {
            badge.innerText = statusText;
            badge.style.background = statusBadgeColor;
            badge.style.color = statusBadgeTextColor;
        }

        const logStatus = document.getElementById('log-status-text');
        if (logStatus) {
            logStatus.innerText = "Conectado e Pronto";
            logStatus.style.color = "var(--success)";
        }

        const logSync = document.getElementById('log-sync-time');
        if (logSync) {
            logSync.innerText = syncTimeText;
        }

        const logRecords = document.getElementById('log-records-count');
        if (logRecords) {
            logRecords.innerText = projects.length.toLocaleString('pt-BR');
        }

        const logGanhosRecords = document.getElementById('log-ganhos-records-count');
        if (logGanhosRecords && typeof Ganhos !== 'undefined') {
            logGanhosRecords.innerText = Ganhos.length.toLocaleString('pt-BR');
        }

        // Exibir/ocultar containers de configuração conforme seleção
        const sheetContainer = document.getElementById('sheet-url-container');
        const uploadContainer = document.getElementById('uploaded-info-container');
        
        if (sheetContainer) sheetContainer.style.display = sourceType === 'sheet' ? 'flex' : 'none';
        if (uploadContainer) uploadContainer.style.display = sourceType === 'upload' ? 'flex' : 'none';

        // Atualizar filtros e dashboard
        populateFilterOptions();
        
        const activeTab = document.querySelector('.nav-item.active') ? document.querySelector('.nav-item.active').getAttribute('data-tab') : 'visao-geral';
        if (activeTab === 'visao-geral') {
            applyFiltersVisaoGeral();
        } else if (activeTab === 'explorador') {
            applyFiltersExplorador();
        } else if (activeTab === 'analise-avancada') {
            applyAnaliseFilters();
        } else if (activeTab === 'ganhos-pi') {
            applyGanhosFilters();
        } else if (activeTab === 'propriedade-intelectual') {
            applyPiFilters();
        } else {
            filteredProjects = [...projects];
        }

        if (alertUser) {
            alert(`Fonte de dados alterada para: ${statusText}\n${projects.length} registros ativos.`);
        }
    }

    // === RECARREGAR/ATUALIZAR DADOS DA FONTE ATIVA ===
    function refreshActiveSourceData() {
        const btnRefresh = document.getElementById('btn-refresh-active-source');
        const originalText = btnRefresh ? btnRefresh.innerHTML : "Atualizar Dados da Fonte";
        
        if (btnRefresh) {
            btnRefresh.disabled = true;
            btnRefresh.innerHTML = `
                <div class="wp-spinner" style="width: 14px; height: 14px; border-width: 2px; margin-right: 6px; display: inline-block; vertical-align: middle;"></div>
                Atualizando...
            `;
        }
        if (activeSourceType === 'default') {
            const officialProjectsUrl = "https://docs.google.com/spreadsheets/d/1PVyTdBjFmtqMMFt4OqiSHhofmOPx15Re_8ddEiNro6U/export?format=csv&gid=409266791&t=" + Date.now() + "&rand=" + Math.random();
            const officialGanhosUrl = "https://docs.google.com/spreadsheets/d/1Ybhp3gQvH1vA8-xBiteq18VgObN3vggv/export?format=csv&gid=1299353642&t=" + Date.now() + "&rand=" + Math.random();

            Promise.all([
                fetch(officialProjectsUrl, { cache: "no-store", headers: { "Cache-Control": "no-cache", "Pragma": "no-cache" } }).then(r => {
                    if (!r.ok) throw new Error("Erro de rede ao acessar planilha de Projetos oficial.");
                    return r.text();
                }),
                fetch(officialGanhosUrl, { cache: "no-store", headers: { "Cache-Control": "no-cache", "Pragma": "no-cache" } }).then(r => {
                    if (!r.ok) throw new Error("Erro de rede ao acessar planilha de Ganhos oficial.");
                    return r.text();
                })
            ])
            .then(([projectsCsv, ganhosCsv]) => {
                // Parse projectsCsv
                const delimiterProj = detectDelimiter(projectsCsv);
                const rowsProj = parseCSVLines(projectsCsv, delimiterProj);
                if (rowsProj.length < 2) throw new Error("A planilha de Projetos oficial retornou dados insuficientes.");
                
                // Parse ganhosCsv
                const delimiterGanhos = detectDelimiter(ganhosCsv);
                const actualRowsGanhos = parseCSVLines(ganhosCsv, delimiterGanhos);
                if (actualRowsGanhos.length < 2) throw new Error("A planilha de Ganhos oficial retornou dados insuficientes.");

                // Map & Load Projects
                const headerRowProj = rowsProj[0];
                const idxMapProj = getHeaderMapping(headerRowProj);
                
                const loadedProjects = [];
                for (let i = 1; i < rowsProj.length; i++) {
                    const row = rowsProj[i];
                    if (!row || row.length === 0 || (row.length === 1 && row[0] === "")) continue;
                    
                    const valAt = (idx) => (idx !== -1 && row[idx] !== undefined && row[idx] !== null) ? row[idx] : "";
                    
                    const rawTitle = valAt(idxMapProj.titulo);
                    if (!rawTitle || rawTitle.toString().toLowerCase().includes("(excluído)") || rawTitle.toString().toLowerCase().includes("registro duplicado")) {
                        continue; 
                    }
                    
                    const rawId = valAt(idxMapProj.id);
                    if (rawId.toString().trim() === "Nº antiga" || rawId.toString().trim() === "Nº" || rawTitle.toString().trim() === "Projeto/Título" || rawTitle.toString().trim() === "Projeto") {
                        continue;
                    }
                    
                    const rawValor = valAt(idxMapProj.valor) || "0";
                    const rawTaxa = valAt(idxMapProj.taxa_ufsm) || "0";
                    const rawAno = valAt(idxMapProj.ano);
                    const rawMes = valAt(idxMapProj.mes);
                    const rawVigenciaIni = valAt(idxMapProj.vigencia_inicial);
                    
                    const pVal = cleanJsCurrency(rawValor.toString());
                    const pTax = cleanJsCurrency(rawTaxa.toString());
                    const pAno = getYearFromVigencia(rawVigenciaIni.toString()) || (parseInt(rawAno.toString()) || null);
                    const pMes = parseInt(rawMes.toString()) || null;
                    
                    const tipoProj = valAt(idxMapProj.tipo_projeto) || "Outro";
                    const situacao = valAt(idxMapProj.situacao) || "Indefinida";
                    const unidade = valAt(idxMapProj.unidade) || "OUTRA";
                    
                    let tipoNorm = "Outro";
                    const tUpper = tipoProj.toString().toUpperCase();
                    if (tUpper.includes("PESQUISA")) tipoNorm = "Pesquisa";
                    else if (tUpper.includes("EXTENS")) tipoNorm = "Extensão";
                    else if (tUpper.includes("DES.") || tUpper.includes("DESENVOLVIMENTO")) tipoNorm = "Des. Institucional";
                    
                    let sitNorm = "Outros";
                    const sUpper = situacao.toString().toUpperCase();
                    if (sUpper.includes("ENCERRADO")) sitNorm = "Encerrado";
                    else if (sUpper.includes("VIGÊNCIA") || sUpper.includes("VIGENCIA") || sUpper.includes("EM VIG")) sitNorm = "Em vigência";
                    else if (sUpper.includes("CANC") || sUpper.includes("ARQ") || sUpper.includes("SUSP")) sitNorm = "Cancelado/Suspenso";
                    
                    let unidNorm = unidade.toString().toUpperCase();
                    if (unidNorm.includes("REITORIA")) unidNorm = "REITORIA";
                    else if (unidNorm.includes("POLI") || unidNorm.includes("COLÉGIO POLITÉCNICO")) unidNorm = "POLITÉCNICO";
                    else if (unidNorm.includes("CTISM")) unidNorm = "CTISM";
                    else if (unidNorm.includes("FW") || unidNorm.includes("FREDERICO")) unidNorm = "UFSM-FW";
                    
                    loadedProjects.push({
                        id: rawId.toString().trim(),
                        n_antiga: fixEncoding((idxMapProj.n_antiga !== -1 && row[idxMapProj.n_antiga]) ? row[idxMapProj.n_antiga].toString().trim() : ""),
                        mes: pMes,
                        ano: pAno,
                        fundacao: fixEncoding((idxMapProj.fundacao !== -1 && row[idxMapProj.fundacao]) ? row[idxMapProj.fundacao].toString().trim() : "SEM FUNDAÇÃO"),
                        tipo_projeto: fixEncoding(tipoProj.toString().trim()),
                        tipo_projeto_norm: fixEncoding(tipoNorm),
                        situacao: fixEncoding(situacao.toString().trim()),
                        situacao_norm: fixEncoding(sitNorm),
                        nup: fixEncoding((idxMapProj.nup !== -1 && row[idxMapProj.nup]) ? row[idxMapProj.nup].toString().trim() : ""),
                        coordenador: normalizeCoordinatorName((idxMapProj.coordenador !== -1 && row[idxMapProj.coordenador]) ? row[idxMapProj.coordenador].toString().trim() : ""),
                        unidade: fixEncoding(unidade.toString().trim()),
                        unid_norm: fixEncoding(unidNorm),
                        subunidade: fixEncoding((idxMapProj.subunidade !== -1 && row[idxMapProj.subunidade]) ? row[idxMapProj.subunidade].toString().trim() : ""),
                        fiscal: fixEncoding((idxMapProj.fiscal !== -1 && row[idxMapProj.fiscal]) ? row[idxMapProj.fiscal].toString().trim() : ""),
                        participes: fixEncoding((idxMapProj.participes !== -1 && row[idxMapProj.participes]) ? row[idxMapProj.participes].toString().trim() : ""),
                        titulo: (() => {
                            const regPortal = (idxMapProj.registro_portal !== -1 && row[idxMapProj.registro_portal]) ? row[idxMapProj.registro_portal].toString().trim() : "";
                            let cleanTitle = rawTitle.toString().trim();
                            if (regPortal && regPortal !== "---") {
                                cleanTitle = regPortal + " - " + cleanTitle;
                            }
                            return fixEncoding(cleanTitle);
                        })(),
                        registro_portal: (idxMapProj.registro_portal !== -1 && row[idxMapProj.registro_portal]) ? row[idxMapProj.registro_portal].toString().trim() : "",
                        valor: pVal,
                        taxa_ufsm: pTax,
                        vigencia_inicial: fixEncoding((idxMapProj.vigencia_inicial !== -1 && row[idxMapProj.vigencia_inicial]) ? row[idxMapProj.vigencia_inicial].toString().trim() : ""),
                        vigencia_final: fixEncoding((idxMapProj.vigencia_final !== -1 && row[idxMapProj.vigencia_final]) ? row[idxMapProj.vigencia_final].toString().trim() : ""),
                        financiador: normalizeFinanciador((idxMapProj.financiador !== -1 && row[idxMapProj.financiador]) ? row[idxMapProj.financiador].toString().trim() : "")
                    });
                }

                // Map & Load Ganhos
                const loadedGanhos = [];
                for (let i = 1; i < actualRowsGanhos.length; i++) {
                    const row = actualRowsGanhos[i];
                    if (!row || row.length === 0 || (row.length === 1 && row[0] === "")) continue;
                    
                    const valAt = (idx) => (row[idx] !== undefined && row[idx] !== null) ? row[idx].toString().trim() : "";
                    
                    const dateStr = valAt(0);
                    if (!dateStr || dateStr.toLowerCase() === "total" || dateStr.toLowerCase() === "data") {
                        continue;
                    }

                    let day = null, mes = null, ano = null;

                    // Parse D/M/YYYY or M/D/YYYY
                    if (/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/.test(dateStr)) {
                        const matches = dateStr.match(/^(\d{1,2})[\/\-](\d{1,2})[\/\-](\d{2,4})$/);
                        let p1 = parseInt(matches[1], 10);
                        let p2 = parseInt(matches[2], 10);
                        ano = parseInt(matches[3], 10);
                        if (ano < 100) {
                            ano += 2000;
                        }
                        // Tratar formato misto D/M/YYYY vs M/D/YYYY de forma inteligente
                        if (p1 > 12) {
                            day = p1;
                            mes = p2;
                        } else if (p2 > 12) {
                            day = p2;
                            mes = p1;
                        } else {
                            // Padrão brasileiro (D/M/YYYY) se ambos forem menores ou iguais a 12
                            day = p1;
                            mes = p2;
                        }
                    }
                    // Parse YYYY-MM-DD
                    else if (/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})$/.test(dateStr)) {
                        const matches = dateStr.match(/^(\d{4})[\/\-](\d{1,2})[\/\-](\d{1,2})$/);
                        ano = parseInt(matches[1], 10);
                        mes = parseInt(matches[2], 10);
                        day = parseInt(matches[3], 10);
                    }

                    if (ano === null || isNaN(ano)) {
                        continue;
                    }

                    const valorTotal = cleanJsCurrency(valAt(4));
                    const valorUfsm = cleanJsCurrency(valAt(5));
                    const valorDept = cleanJsCurrency(valAt(6));
                    const valorInventor = cleanJsCurrency(valAt(7));

                    // If all values are 0, skip
                    if (valorTotal === 0 && valorUfsm === 0 && valorDept === 0 && valorInventor === 0) {
                        continue;
                    }

                    loadedGanhos.push({
                        data: dateStr,
                        dia: day,
                        mes: mes,
                        ano: ano,
                        descricao: fixEncoding(valAt(1)),
                        departamento: fixEncoding(valAt(2)),
                        fundacao: fixEncoding(valAt(3)),
                        valor_total: valorTotal,
                        valor_ufsm: valorUfsm,
                        valor_departamento: valorDept,
                        valor_inventor: valorInventor
                    });
                }

                originalProjects = loadedProjects;
                Ganhos = loadedGanhos;
                
                localStorage.setItem('default_projects_data', JSON.stringify(loadedProjects));
                localStorage.setItem('default_ganhos_data', JSON.stringify(loadedGanhos));
                
                applyActiveSource('default', false);
                alert("Dados de Projetos e Ganhos Econômicos PI atualizados em tempo real diretamente das Planilhas Google oficiais!");
                
                if (btnRefresh) {
                    btnRefresh.disabled = false;
                    btnRefresh.innerHTML = originalText;
                }
            })
            .catch(err => {
                console.warn("Falha ao sincronizar online. Usando fallback local: ", err);
                
                // Fallback: Carregar localmente do data.js e ganhos_data.js usando injeção de script
                const existingScriptProj = document.getElementById('data-js-reload-script');
                if (existingScriptProj) existingScriptProj.remove();

                const existingScriptGanhos = document.getElementById('ganhos-data-js-reload-script');
                if (existingScriptGanhos) existingScriptGanhos.remove();

                let loadedCount = 0;
                const totalScripts = 2;

                const checkAndApply = () => {
                    loadedCount++;
                    if (loadedCount === totalScripts) {
                        if (typeof initialProjectsData !== 'undefined' && typeof initialGanhosData !== 'undefined') {
                            originalProjects = initialProjectsData.map(p => {
                                const extractedAno = getYearFromVigencia(p.vigencia_inicial) || p.ano;
                                const extractedMes = getMonthFromVigencia(p.vigencia_inicial) || p.mes;
                                return {
                                    ...p,
                                    ano: extractedAno,
                                    mes: extractedMes,
                                    coordenador: normalizeCoordinatorName(p.coordenador),
                                    titulo: (p.registro_portal && p.registro_portal !== "---" && !fixEncoding(p.titulo).startsWith(p.registro_portal)) ? `${p.registro_portal} - ${fixEncoding(p.titulo)}` : fixEncoding(p.titulo),
                                    situacao: fixEncoding(p.situacao),
                                    situacao_norm: fixEncoding(p.situacao_norm),
                                    tipo_projeto: fixEncoding(p.tipo_projeto),
                                    tipo_projeto_norm: fixEncoding(p.tipo_projeto_norm),
                                    fundacao: fixEncoding(p.fundacao),
                                    unidade: fixEncoding(p.unidade),
                                    unid_norm: fixEncoding(p.unid_norm),
                                    subunidade: fixEncoding(p.subunidade),
                                    fiscal: fixEncoding(p.fiscal),
                                    participes: fixEncoding(p.participes),
                                    financiador: normalizeFinanciador(p.financiador),
                                    tipo_contrato: fixEncoding(p.tipo_contrato)
                                };
                            });

                            Ganhos = initialGanhosData.map(g => {
                                return {
                                    ...g,
                                    descricao: fixEncoding(g.descricao),
                                    departamento: fixEncoding(g.departamento),
                                    fundacao: fixEncoding(g.fundacao)
                                };
                            });

                            localStorage.setItem('default_projects_data', JSON.stringify(originalProjects));
                            localStorage.setItem('default_ganhos_data', JSON.stringify(Ganhos));
                            applyActiveSource('default', false);
                            alert("Sincronização online indisponível (comum em execução local file:// devido a bloqueio CORS).\n\nOs dados foram carregados com sucesso a partir dos arquivos locais (data.js e ganhos_data.js).\n\nPara carregar novos dados inseridos nas Planilhas Google para o sistema, execute o arquivo 'atualizar_dados.bat' na pasta do projeto e depois clique em Atualizar novamente!");
                        } else {
                            alert("Erro ao ler os dados dos fallbacks locais.");
                        }

                        if (btnRefresh) {
                            btnRefresh.disabled = false;
                            btnRefresh.innerHTML = originalText;
                        }
                    }
                };

                const scriptProj = document.createElement('script');
                scriptProj.id = 'data-js-reload-script';
                scriptProj.src = 'data.js?t=' + Date.now();
                scriptProj.onload = checkAndApply;
                scriptProj.onerror = () => {
                    console.error("Erro ao carregar data.js");
                    if (btnRefresh) {
                        btnRefresh.disabled = false;
                        btnRefresh.innerHTML = originalText;
                    }
                };

                const scriptGanhos = document.createElement('script');
                scriptGanhos.id = 'ganhos-data-js-reload-script';
                scriptGanhos.src = 'ganhos_data.js?t=' + Date.now();
                scriptGanhos.onload = checkAndApply;
                scriptGanhos.onerror = () => {
                    console.error("Erro ao carregar ganhos_data.js");
                    if (btnRefresh) {
                        btnRefresh.disabled = false;
                        btnRefresh.innerHTML = originalText;
                    }
                };

                document.body.appendChild(scriptProj);
                document.body.appendChild(scriptGanhos);
            });
        } else if (activeSourceType === 'sheet') {
            const savedSheetUrl = localStorage.getItem('sheet_url');
            if (savedSheetUrl) {
                // Sincroniza a planilha do Google Sheets novamente
                syncGoogleSheet(savedSheetUrl);
                // Restaura o botão ao normal
                if (btnRefresh) {
                    btnRefresh.disabled = false;
                    btnRefresh.innerHTML = originalText;
                }
            } else {
                alert("Nenhum link de Google Planilhas configurado!");
                if (btnRefresh) {
                    btnRefresh.disabled = false;
                    btnRefresh.innerHTML = originalText;
                }
            }
        } else if (activeSourceType === 'upload') {
            // Mostra o diálogo de arquivo para o usuário re-selecionar o arquivo local atualizado
            const fileInput = document.getElementById('csv-file-input');
            if (fileInput) {
                alert("Para atualizar a fonte de dados do arquivo local, selecione o arquivo correspondente atualizado em seu computador.");
                fileInput.click();
            }
            if (btnRefresh) {
                btnRefresh.disabled = false;
                btnRefresh.innerHTML = originalText;
            }
        }
    }

    // === PROCESSAR DADOS DO LIVRO DE TRABALHO (MULTI-ABA) ===
    function loadWorkbookData(sheets, filename, sourceType) {
        if (!sheets || Object.keys(sheets).length === 0) {
            alert("Erro: O arquivo não possui planilhas ou abas válidas!");
            return;
        }

        // Inicializa o estado de importação pendente
        pendingImportData = {
            filename: filename,
            sourceType: sourceType,
            sheets: sheets,
            selectedSheets: Object.keys(sheets), // seleciona todas por padrão
            activeSheetName: Object.keys(sheets)[0]
        };

        showPowerQueryPreviewModal();
    }

    // === EXIBIR MODAL DE PRÉ-VISUALIZAÇÃO ESTILO POWER QUERY ===
    function showPowerQueryPreviewModal() {
        if (!pendingImportData) return;
        const { filename, sheets, selectedSheets, activeSheetName } = pendingImportData;

        // Atualizar nome do arquivo no modal
        const filenameEl = document.getElementById("preview-filename");
        if (filenameEl) filenameEl.innerText = filename;

        // Renderizar navegador de abas (painel esquerdo)
        const sheetListEl = document.getElementById("preview-sheet-list");
        if (sheetListEl) {
            sheetListEl.innerHTML = "";
            Object.keys(sheets).forEach(sheetName => {
                const rows = sheets[sheetName];
                const rowCount = rows.length > 0 ? rows.length - 1 : 0; // desconta cabeçalho

                const itemDiv = document.createElement("div");
                itemDiv.className = `power-query-sheet-item ${sheetName === activeSheetName ? 'selected' : ''}`;
                itemDiv.setAttribute("data-sheet-name", sheetName);

                const leftDiv = document.createElement("div");
                leftDiv.className = "power-query-sheet-item-left";

                const checkbox = document.createElement("input");
                checkbox.type = "checkbox";
                checkbox.className = "power-query-checkbox sheet-select-checkbox";
                checkbox.checked = selectedSheets.includes(sheetName);
                checkbox.setAttribute("data-sheet", sheetName);
                
                // Evita bolha de clique no checkbox para não mudar a aba ativa sem querer
                checkbox.addEventListener('click', (e) => {
                    e.stopPropagation();
                    toggleSheetSelection(sheetName, checkbox.checked);
                });

                const sheetIcon = `<svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" style="width: 16px; height: 16px; color: var(--text-muted); flex-shrink:0;">
                    <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M9 12h6m-6 4h6m2 5H7a2 2 0 01-2-2V5a2 2 0 012-2h5.586a1 1 0 01.707.293l5.414 5.414a1 1 0 01.293.707V19a2 2 0 01-2 2z" />
                </svg>`;

                const nameSpan = document.createElement("span");
                nameSpan.className = "power-query-sheet-name";
                nameSpan.innerText = sheetName;
                nameSpan.title = sheetName;

                leftDiv.appendChild(checkbox);
                leftDiv.innerHTML += sheetIcon;
                leftDiv.appendChild(nameSpan);

                const countSpan = document.createElement("span");
                countSpan.style.fontSize = "10.5px";
                countSpan.style.color = "var(--text-muted)";
                countSpan.innerText = `${rowCount} reg`;

                itemDiv.appendChild(leftDiv);
                itemDiv.appendChild(countSpan);

                // Clique no item para carregar a pré-visualização ativa
                itemDiv.addEventListener('click', () => {
                    changeActivePreviewSheet(sheetName);
                });

                sheetListEl.appendChild(itemDiv);
            });
        }

        // Sincronizar checkbox de "Selecionar Todas"
        const selectAllCheckbox = document.getElementById("preview-select-all");
        if (selectAllCheckbox) {
            const allSheetNames = Object.keys(sheets);
            selectAllCheckbox.checked = allSheetNames.every(name => selectedSheets.includes(name));
            
            selectAllCheckbox.onchange = (e) => {
                const isChecked = e.target.checked;
                if (isChecked) {
                    pendingImportData.selectedSheets = [...allSheetNames];
                } else {
                    pendingImportData.selectedSheets = [];
                }

                // Atualizar checkboxes visuais da lista
                const checkboxes = document.querySelectorAll(".sheet-select-checkbox");
                checkboxes.forEach(cb => cb.checked = isChecked);

                updateMappingWarnings();
            };
        }

        // Renderizar grid de dados da aba ativa
        renderActiveSheetPreview();

        // Atualizar avisos de mapeamento
        updateMappingWarnings();

        // Mostrar o Modal
        const modal = document.getElementById("import-preview-modal");
        if (modal) {
            modal.style.display = "flex";
            setTimeout(() => modal.classList.add("active"), 10);
        }
    }

    // === ALTERAR A ABA EM PRÉ-VISUALIZAÇÃO ===
    function changeActivePreviewSheet(sheetName) {
        if (!pendingImportData) return;
        pendingImportData.activeSheetName = sheetName;
        
        // Atualizar classe selecionada no painel esquerdo
        const items = document.querySelectorAll(".power-query-sheet-item");
        items.forEach(item => {
            if (item.getAttribute("data-sheet-name") === sheetName) {
                item.classList.add("selected");
            } else {
                item.classList.remove("selected");
            }
        });

        // Atualizar grid da aba ativa
        renderActiveSheetPreview();
    }

    // === MARCAR OU DESMARCAR UMA ABA DO WORKBOOK ===
    function toggleSheetSelection(sheetName, isChecked) {
        if (!pendingImportData) return;
        const selected = pendingImportData.selectedSheets;
        if (isChecked) {
            if (!selected.includes(sheetName)) {
                selected.push(sheetName);
            }
        } else {
            const idx = selected.indexOf(sheetName);
            if (idx !== -1) {
                selected.splice(idx, 1);
            }
        }

        // Sincronizar checkbox de "Selecionar Todas"
        const selectAllCheckbox = document.getElementById("preview-select-all");
        if (selectAllCheckbox) {
            const allNames = Object.keys(pendingImportData.sheets);
            selectAllCheckbox.checked = allNames.every(name => selected.includes(name));
        }

        updateMappingWarnings();
    }

    // === RETORNAR O MAPEAMENTO DINÂMICO DOS CABEÇALHOS ===
    function getHeaderMapping(headerRow) {
        const header = Array.from(headerRow || []).map(h => h ? h.toString().trim().toLowerCase() : "");
        
        const idxMap = {
            id: -1,
            n_antiga: -1,
            mes: -1,
            ano: -1,
            fundacao: -1,
            tipo_projeto: -1,
            situacao: -1,
            nup: -1,
            coordenador: -1,
            unidade: -1,
            subunidade: -1,
            fiscal: -1,
            participes: -1,
            titulo: -1,
            registro_portal: -1,
            valor: -1,
            taxa_ufsm: -1,
            vigencia_inicial: -1,
            vigencia_final: -1,
            financiador: -1
        };

        header.forEach((h, idx) => {
            if (!h) return;
            const hClean = fixEncoding(h);
            const hLower = hClean.toLowerCase();
            
            if (hLower === "id" || hLower === "nº" || hLower === "nº." || hLower === "num" || hLower === "numero" || hLower === "número" || hLower === "h1" || hLower === "código" || hLower === "codigo") {
                idxMap.id = idx;
            }
            else if (hLower.includes("antiga")) idxMap.n_antiga = idx;
            else if (hLower.includes("mês") || hLower.includes("mes")) idxMap.mes = idx;
            else if (hLower.includes("ano")) idxMap.ano = idx;
            else if (hLower.includes("funda")) idxMap.fundacao = idx;
            else if (hLower.includes("tipo") && hLower.includes("projeto")) idxMap.tipo_projeto = idx;
            else if (hLower.includes("situa")) idxMap.situacao = idx;
            else if (hLower.includes("nup")) idxMap.nup = idx;
            else if (hLower.includes("coordenador") && !hLower.includes("contato")) idxMap.coordenador = idx;
            else if (hLower.includes("unidade") || hLower.includes("centro")) idxMap.unidade = idx;
            else if (hLower.includes("subunidade")) idxMap.subunidade = idx;
            else if (hLower.includes("fiscal")) idxMap.fiscal = idx;
            else if (hLower.includes("partícipe") || hLower.includes("participe")) idxMap.participes = idx;
            else if (hLower.includes("portal") || hLower.includes("registro")) idxMap.registro_portal = idx;
            else if (hLower.includes("título") || hLower.includes("titulo") || (hLower.includes("projeto") && hLower.includes("título")) || hLower === "projeto" || hLower === "nome do projeto" || hLower === "nome") idxMap.titulo = idx;
            else if (hLower.includes("valor") || hLower.includes("custo")) idxMap.valor = idx;
            else if (hLower.includes("taxa")) idxMap.taxa_ufsm = idx;
            else if (hLower.includes("vigência inicial") || hLower.includes("vigencia inicial") || hLower.includes("inicio") || hLower.includes("início")) idxMap.vigencia_inicial = idx;
            else if (hLower.includes("vigência final") || hLower.includes("vigencia final") || hLower.includes("fim") || hLower.includes("termino") || hLower.includes("término")) idxMap.vigencia_final = idx;
            else if (hLower.includes("financiador") || hLower.includes("edital") || hLower.includes("agência") || hLower.includes("agencia")) idxMap.financiador = idx;
        });

        // Fallback defaults se não encontrados exatamente
        if (idxMap.id === -1) {
            idxMap.id = 0; // Primeira coluna por padrão
        }
        if (idxMap.titulo === -1) {
            const tIdx = header.findIndex(h => h && (h.includes("projeto") || h.includes("título") || h.includes("titulo") || h.includes("nome")));
            if (tIdx !== -1) {
                idxMap.titulo = tIdx;
            }
        }

        return idxMap;
    }

    // === RENDERIZAR PRÉ-VISUALIZAÇÃO DA ABA ATIVA COM CABEÇALHOS DO SISTEMA ===
    function renderActiveSheetPreview() {
        if (!pendingImportData) return;
        const { sheets, activeSheetName } = pendingImportData;
        const rows = sheets[activeSheetName] || [];

        // Atualizar nome da aba ativa no cabeçalho do grid
        const activeSheetNameEl = document.getElementById("preview-active-sheet-name");
        if (activeSheetNameEl) activeSheetNameEl.innerText = activeSheetName;

        const rowCountEl = document.getElementById("preview-sheet-row-count");
        if (rowCountEl) {
            const count = rows.length > 0 ? rows.length - 1 : 0;
            rowCountEl.innerText = `${count} registros`;
        }

        const previewThead = document.getElementById("preview-data-thead");
        const previewTbody = document.getElementById("preview-data-tbody");

        if (!previewThead || !previewTbody) return;
        previewThead.innerHTML = "";
        previewTbody.innerHTML = "";

        if (rows.length === 0) {
            previewTbody.innerHTML = `<tr><td colspan="5" style="text-align: center; color: var(--text-muted); padding: 20px;">Esta aba está vazia.</td></tr>`;
            return;
        }

        const headerRow = rows[0];
        const idxMap = getHeaderMapping(headerRow);

        const systemFieldsMetadata = {
            id: { label: "ID", required: true },
            titulo: { label: "Projeto / Título", required: true },
            coordenador: { label: "Coordenador", required: true },
            valor: { label: "Valor (R$)", required: true },
            fundacao: { label: "Fundação", required: false },
            tipo_projeto: { label: "Tipo de Projeto", required: false },
            situacao: { label: "Situação", required: false },
            unidade: { label: "Unidade / Centro", required: false },
            subunidade: { label: "Subunidade", required: false },
            vigencia_inicial: { label: "Vigência Inicial", required: false },
            vigencia_final: { label: "Vigência Final", required: false },
            taxa_ufsm: { label: "Taxa UFSM", required: false },
            fiscal: { label: "Fiscal", required: false },
            participes: { label: "Partícipes", required: false },
            financiador: { label: "Financiador / Edital", required: false },
            nup: { label: "NUP", required: false },
            mes: { label: "Mês", required: false },
            ano: { label: "Ano", required: false },
            n_antiga: { label: "Nº Antiga", required: false }
        };

        // Renderizar cabeçalhos com mapeamento
        const trHead = document.createElement("tr");
        headerRow.forEach((rawHeader, colIdx) => {
            const th = document.createElement("th");
            th.style.padding = "12px 16px";
            th.style.verticalAlign = "top";
            
            // Verifica se este índice de coluna mapeia para algum campo do sistema
            let matchedKey = null;
            Object.keys(idxMap).forEach(key => {
                if (idxMap[key] === colIdx) {
                    matchedKey = key;
                }
            });

            const cleanRawHeader = rawHeader ? fixEncoding(rawHeader.toString().trim()) : `Coluna ${colIdx + 1}`;

            if (matchedKey) {
                const meta = systemFieldsMetadata[matchedKey];
                const requiredAsterisk = meta.required ? '<span style="color: var(--danger); margin-left: 2px;">*</span>' : '';
                th.innerHTML = `
                    <div style="display: flex; flex-direction: column; gap: 2px; text-align: left;">
                        <span style="color: var(--primary); font-weight: 700; font-size: 12px;">${meta.label}${requiredAsterisk}</span>
                        <span class="power-query-table-header-info">[${cleanRawHeader}]</span>
                    </div>
                `;
            } else {
                th.innerHTML = `
                    <div style="display: flex; flex-direction: column; gap: 2px; text-align: left;">
                        <span style="color: var(--text-secondary); font-weight: 500; font-size: 12px;">${cleanRawHeader}</span>
                        <span class="power-query-table-header-info" style="color: var(--text-muted);">(Ignorada)</span>
                    </div>
                `;
            }

            trHead.appendChild(th);
        });
        previewThead.appendChild(trHead);

        // Renderizar linhas de amostra (até 15 linhas)
        const sampleRowsCount = Math.min(rows.length, 16); // Cabeçalho + 15
        for (let i = 1; i < sampleRowsCount; i++) {
            const rowData = rows[i];
            if (!rowData) continue;
            const tr = document.createElement("tr");
            
            headerRow.forEach((_, colIdx) => {
                const td = document.createElement("td");
                td.style.padding = "10px 16px";
                const cellValue = rowData[colIdx] !== undefined ? rowData[colIdx].toString().trim() : "";
                td.innerText = fixEncoding(cellValue);
                tr.appendChild(td);
            });
            previewTbody.appendChild(tr);
        }
    }

    // === ATUALIZAR MENSAGENS E CAIXAS DE AVISO DE MAPEAMENTO ===
    function updateMappingWarnings() {
        if (!pendingImportData) return;
        const { sheets, selectedSheets } = pendingImportData;
        const warningBox = document.getElementById("preview-warning-box");
        if (!warningBox) return;

        const sheetsWithMissingFields = [];

        selectedSheets.forEach(sheetName => {
            const rows = sheets[sheetName] || [];
            if (rows.length === 0) return;
            
            const idxMap = getHeaderMapping(rows[0]);
            const missingRequired = [];

            if (idxMap.id === -1) missingRequired.push("ID");
            if (idxMap.titulo === -1) missingRequired.push("Projeto / Título");
            if (idxMap.coordenador === -1) missingRequired.push("Coordenador");
            if (idxMap.valor === -1) missingRequired.push("Valor");

            if (missingRequired.length > 0) {
                sheetsWithMissingFields.push({
                    name: sheetName,
                    fields: missingRequired
                });
            }
        });

        if (sheetsWithMissingFields.length > 0) {
            warningBox.style.display = "block";
            
            const listHtml = sheetsWithMissingFields.map(item => {
                return `<strong>${item.name}</strong> (Ausente: ${item.fields.join(", ")})`;
            }).join("; ");

            warningBox.innerHTML = `
                <div style="display: flex; align-items: flex-start; gap: 8px;">
                    <svg xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24" stroke="currentColor" style="width: 18px; height: 18px; flex-shrink: 0; margin-top: 1px;">
                        <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z" />
                    </svg>
                    <div>
                        <strong style="font-weight: 700;">Aviso de Mapeamento:</strong> 
                        Algumas abas selecionadas não possuem todos os campos obrigatórios (*ID, Projeto, Coordenador, Valor*): ${listHtml}. Verifique os cabeçalhos dessas abas antes de carregar.
                    </div>
                </div>
            `;
        } else {
            warningBox.style.display = "none";
        }
    }

    function closeImportPreviewModal() {
        pendingImportData = null;
        const modal = document.getElementById("import-preview-modal");
        if (modal) {
            modal.classList.remove("active");
            setTimeout(() => modal.style.display = "none", 300);
        }
        const input = document.getElementById("csv-file-input");
        if (input) input.value = "";
    }

    function executeImportPreviewConfirm() {
        if (!pendingImportData) return;
        const { sheets, selectedSheets, filename, sourceType } = pendingImportData;
        
        if (selectedSheets.length === 0) {
            alert("Nenhuma aba selecionada para importação! Selecione pelo menos uma aba.");
            return;
        }

        const modal = document.getElementById("import-preview-modal");
        if (modal) {
            modal.classList.remove("active");
            setTimeout(() => {
                modal.style.display = "none";
                executeWorkbookImport(sheets, selectedSheets, filename, sourceType);
            }, 300);
        } else {
            executeWorkbookImport(sheets, selectedSheets, filename, sourceType);
        }
        pendingImportData = null;
    }

    // === EXECUÇÃO CONSOLIDADA DA IMPORTAÇÃO MULTI-ABA ===
    function executeWorkbookImport(sheets, selectedSheets, filename, sourceType) {
        try {
            const consolidatedProjects = [];

            selectedSheets.forEach(sheetName => {
                const rows = sheets[sheetName] || [];
                if (rows.length < 2) return; // ignora abas sem dados suficientes

                const headerRow = rows[0];
                const idxMap = getHeaderMapping(headerRow);

                for (let i = 1; i < rows.length; i++) {
                    const row = rows[i];
                    if (!row || row.length === 0 || (row.length === 1 && row[0] === "")) continue;

                    const valAt = (idx) => (idx !== -1 && row[idx] !== undefined && row[idx] !== null) ? row[idx] : "";

                    const rawTitle = valAt(idxMap.titulo);
                    if (!rawTitle || rawTitle.toString().toLowerCase().includes("(excluído)") || rawTitle.toString().toLowerCase().includes("registro duplicado")) {
                        continue; 
                    }

                    const rawId = valAt(idxMap.id);
                    if (rawId.toString().trim() === "Nº antiga" || rawId.toString().trim() === "Nº" || rawTitle.toString().trim() === "Projeto/Título" || rawTitle.toString().trim() === "Projeto") {
                        continue;
                    }

                    const rawValor = valAt(idxMap.valor) || "0";
                    const rawTaxa = valAt(idxMap.taxa_ufsm) || "0";
                    const rawAno = valAt(idxMap.ano);
                    const rawMes = valAt(idxMap.mes);
                    const rawVigenciaIni = valAt(idxMap.vigencia_inicial);

                    const pVal = cleanJsCurrency(rawValor.toString());
                    const pTax = cleanJsCurrency(rawTaxa.toString());
                    const pAno = getYearFromVigencia(rawVigenciaIni.toString()) || (parseInt(rawAno.toString()) || null);
                    const pMes = parseInt(rawMes.toString()) || null;

                    const tipoProj = valAt(idxMap.tipo_projeto) || "Outro";
                    const situacao = valAt(idxMap.situacao) || "Indefinida";
                    const unidade = valAt(idxMap.unidade) || "OUTRA";

                    let tipoNorm = "Outro";
                    const tUpper = tipoProj.toString().toUpperCase();
                    if (tUpper.includes("PESQUISA")) tipoNorm = "Pesquisa";
                    else if (tUpper.includes("EXTENS")) tipoNorm = "Extensão";
                    else if (tUpper.includes("DES.") || tUpper.includes("DESENVOLVIMENTO")) tipoNorm = "Des. Institucional";

                    let sitNorm = "Outros";
                    const sUpper = situacao.toString().toUpperCase();
                    if (sUpper.includes("ENCERRADO")) sitNorm = "Encerrado";
                    else if (sUpper.includes("VIGÊNCIA") || sUpper.includes("VIGENCIA") || sUpper.includes("EM VIG")) sitNorm = "Em vigência";
                    else if (sUpper.includes("CANC") || sUpper.includes("ARQ") || sUpper.includes("SUSP")) sitNorm = "Cancelado/Suspenso";

                    let unidNorm = unidade.toString().toUpperCase();
                    if (unidNorm.includes("REITORIA")) unidNorm = "REITORIA";
                    else if (unidNorm.includes("POLI") || unidNorm.includes("COLÉGIO POLITÉCNICO")) unidNorm = "POLITÉCNICO";
                    else if (unidNorm.includes("CTISM")) unidNorm = "CTISM";
                    else if (unidNorm.includes("FW") || unidNorm.includes("FREDERICO")) unidNorm = "UFSM-FW";

                    const newProj = {
                        id: rawId.toString().trim(),
                        n_antiga: fixEncoding((idxMap.n_antiga !== -1 && row[idxMap.n_antiga]) ? row[idxMap.n_antiga].toString().trim() : ""),
                        mes: pMes,
                        ano: pAno,
                        fundacao: fixEncoding((idxMap.fundacao !== -1 && row[idxMap.fundacao]) ? row[idxMap.fundacao].toString().trim() : "SEM FUNDAÇÃO"),
                        tipo_projeto: fixEncoding(tipoProj.toString().trim()),
                        tipo_projeto_norm: fixEncoding(tipoNorm),
                        situacao: fixEncoding(situacao.toString().trim()),
                        situacao_norm: fixEncoding(sitNorm),
                        nup: fixEncoding((idxMap.nup !== -1 && row[idxMap.nup]) ? row[idxMap.nup].toString().trim() : ""),
                        coordenador: normalizeCoordinatorName((idxMap.coordenador !== -1 && row[idxMap.coordenador]) ? row[idxMap.coordenador].toString().trim() : ""),
                        unidade: fixEncoding(unidade.toString().trim()),
                        unid_norm: fixEncoding(unidNorm),
                        subunidade: fixEncoding((idxMap.subunidade !== -1 && row[idxMap.subunidade]) ? row[idxMap.subunidade].toString().trim() : ""),
                        fiscal: fixEncoding((idxMap.fiscal !== -1 && row[idxMap.fiscal]) ? row[idxMap.fiscal].toString().trim() : ""),
                        participes: fixEncoding((idxMap.participes !== -1 && row[idxMap.participes]) ? row[idxMap.participes].toString().trim() : ""),
                        titulo: (() => {
                            const regPortal = (idxMap.registro_portal !== -1 && row[idxMap.registro_portal]) ? row[idxMap.registro_portal].toString().trim() : "";
                            let cleanTitle = rawTitle.toString().trim();
                            if (regPortal && regPortal !== "---") {
                                cleanTitle = regPortal + " - " + cleanTitle;
                            }
                            return fixEncoding(cleanTitle);
                        })(),
                        registro_portal: (idxMap.registro_portal !== -1 && row[idxMap.registro_portal]) ? row[idxMap.registro_portal].toString().trim() : "",
                        valor: pVal,
                        taxa_ufsm: pTax,
                        vigencia_inicial: fixEncoding((idxMap.vigencia_inicial !== -1 && row[idxMap.vigencia_inicial]) ? row[idxMap.vigencia_inicial].toString().trim() : ""),
                        vigencia_final: fixEncoding((idxMap.vigencia_final !== -1 && row[idxMap.vigencia_final]) ? row[idxMap.vigencia_final].toString().trim() : ""),
                        financiador: normalizeFinanciador((idxMap.financiador !== -1 && row[idxMap.financiador]) ? row[idxMap.financiador].toString().trim() : "")
                    };

                    consolidatedProjects.push(newProj);
                }
            });

            console.log(`Planilha processada com sucesso: ${consolidatedProjects.length} linhas combinadas.`);

            const now = new Date();
            const timeString = now.toLocaleDateString('pt-BR') + ' às ' + now.toLocaleTimeString('pt-BR', {hour: '2-digit', minute:'2-digit'});

            if (sourceType === 'upload') {
                uploadedProjects = consolidatedProjects;
                localStorage.setItem('uploaded_projects_data', JSON.stringify(consolidatedProjects));
                localStorage.setItem('uploaded_file_name', filename);
                localStorage.setItem('upload_sync_time', timeString);

                const uploadedNameEl = document.getElementById('uploaded-file-name');
                const uploadedRowsEl = document.getElementById('uploaded-file-rows');
                if (uploadedNameEl) uploadedNameEl.innerText = filename;
                if (uploadedRowsEl) uploadedRowsEl.innerText = `${consolidatedProjects.length} registros`;
            } else if (sourceType === 'sheet') {
                sheetProjects = consolidatedProjects;
                localStorage.setItem('sheet_projects_data', JSON.stringify(consolidatedProjects));
                localStorage.setItem('sheet_sync_time', timeString);
            }

            // Aplicar a nova fonte de dados imediatamente
            applyActiveSource(sourceType, false);

            // Mudar para aba Visão Geral automaticamente
            document.querySelector('.nav-item[data-tab="visao-geral"]').click();

            alert(`Parabéns! Planilha "${filename}" importada e ativada com sucesso!\nForam carregados ${consolidatedProjects.length} projetos de ${selectedSheets.length} aba(s) no dashboard.`);

        } catch (err) {
            console.error(err);
            alert(`Erro grave ao analisar a planilha: ${err.message}`);
        }
    }

    // === AUXILIAR: PARSE DE LINHAS CSV RESPEITANDO ASPAS E CARACTERES ===
    function parseCSVLines(text, delimiter) {
        const lines = [];
        let row = [""];
        let inQuotes = false;

        for (let i = 0; i < text.length; i++) {
            const char = text[i];
            const nextChar = text[i + 1];

            if (char === '"') {
                if (inQuotes && nextChar === '"') {
                    // Tratar aspas duplas escapadas ("")
                    row[row.length - 1] += '"';
                    i++;
                } else {
                    // Inverter flag de aspas
                    inQuotes = !inQuotes;
                }
            } else if (char === delimiter && !inQuotes) {
                row.push("");
            } else if ((char === '\r' || char === '\n') && !inQuotes) {
                if (char === '\r' && nextChar === '\n') {
                    i++; // Pular \n complementar do Windows (\r\n)
                }
                lines.push(row);
                row = [""];
            } else {
                row[row.length - 1] += char;
            }
        }
        
        // Adicionar última linha
        if (row.length > 1 || row[0] !== "") {
            lines.push(row);
        }

        return lines;
    }

    function cleanJsCurrency(val) {
        if (!val) return 0;
        let cleaned = val.toString().trim();
        if (cleaned === "---" || cleaned.includes('#VALUE')) return 0;
        cleaned = cleaned.replace("R$", "")
                         .replace(/[\r\n]+/g, "")
                         .replace(/\./g, "")
                         .replace(",", ".")
                         .replace(/\s/g, "");
        cleaned = cleaned.replace(/[^\d.-]/g, '');
        const res = parseFloat(cleaned);
        return isNaN(res) ? 0 : res;
    }

    // === EXTRAIR ANO DA VIGENCIA INICIAL ===
    function getYearFromVigencia(vigenciaIni) {
        if (!vigenciaIni || typeof vigenciaIni !== 'string') return null;
        const trimmed = vigenciaIni.trim();
        // Caso esteja formatado como DD/MM/YYYY
        if (trimmed.includes('/')) {
            const parts = trimmed.split('/');
            if (parts.length === 3) {
                const year = parseInt(parts[2]);
                if (!isNaN(year)) return year;
            }
        }
        // Caso esteja formatado como YYYY-MM-DD
        if (trimmed.includes('-')) {
            const parts = trimmed.split('-');
            if (parts.length === 3) {
                if (parts[0].length === 4) {
                    const year = parseInt(parts[0]);
                    if (!isNaN(year)) return year;
                } else if (parts[2].length === 4) {
                    const year = parseInt(parts[2]);
                    if (!isNaN(year)) return year;
                }
            }
        }
        // Fallback: tentar extrair qualquer número de 4 dígitos consecutivos
        const match = trimmed.match(/\b(20\d{2}|19\d{2})\b/);
        if (match) {
            return parseInt(match[0]);
        }
        return null;
    }

    // === EXTRAIR MÊS DA VIGENCIA INICIAL ===
    function getMonthFromVigencia(vigenciaIni) {
        if (!vigenciaIni || typeof vigenciaIni !== 'string') return null;
        const trimmed = vigenciaIni.trim();
        // Caso esteja formatado como DD/MM/YYYY
        if (trimmed.includes('/')) {
            const parts = trimmed.split('/');
            if (parts.length === 3) {
                const month = parseInt(parts[1]);
                if (!isNaN(month) && month >= 1 && month <= 12) return month;
            }
        }
        // Caso esteja formatado como YYYY-MM-DD
        if (trimmed.includes('-')) {
            const parts = trimmed.split('-');
            if (parts.length === 3) {
                if (parts[0].length === 4) {
                    const month = parseInt(parts[1]);
                    if (!isNaN(month) && month >= 1 && month <= 12) return month;
                } else if (parts[2].length === 4) {
                    const month = parseInt(parts[1]);
                    if (!isNaN(month) && month >= 1 && month <= 12) return month;
                }
            }
        }
        return null;
    }

