                    totalPedidos += pi.total || 0;
                    patentes += pi.patente || 0;
                    software += pi.programa_computador || 0;
                    desenho += pi.desenho_industrial || 0;
                    marcas += pi.marca || 0;
                    cultivares += pi.cultivar || 0;
