            function renderPiTable() {
                const tbody = document.getElementById('pi-details-table-body');
                if (!tbody) return;
                tbody.innerHTML = '';

                const activeDataset = (piActiveSource === 'concedidos') ? filteredPiConcedidos : filteredPi;
                const sortedPi = [...activeDataset].sort((a, b) => a.ano.localeCompare(b.ano));

                sortedPi.forEach(pi => {
                    const tr = document.createElement('tr');
                    tr.innerHTML = 
                        '<td><span style="font-weight:600; color:var(--text-secondary);">' + pi.ano + '</span></td>' +
                        '<td>' + (pi.patente || 0).toLocaleString('pt-BR') + '</td>' +
                        '<td>' + (pi.programa_computador || 0).toLocaleString('pt-BR') + '</td>' +
                        '<td>' + (pi.desenho_industrial || 0).toLocaleString('pt-BR') + '</td>' +
                        '<td>' + (pi.marca || 0).toLocaleString('pt-BR') + '</td>' +
                        '<td>' + (pi.cultivar || 0).toLocaleString('pt-BR') + '</td>' +
                        '<td style="font-weight:700; color:var(--text-primary);">' + (pi.total || 0).toLocaleString('pt-BR') + '</td>';
                    tbody.appendChild(tr);
                });
            }

